[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/logical-record/observations> ;
            sh:resultMessage "A DDI-CDI LogicalRecord should reference at least one cdi:has (the InstanceVariables / VariableMeasured making up the Logical Record)" ;
